class Solution {
   public:
      vector<int> recover(vector<int>& nums)
      {
         vector<int> res; res.resize(nums.size());
         int count = 0;
         for (int i = 0; i < nums.size(); i++)
         {
            if (nums[i] == 0)
               count++;
            else
               res[i] = 1;
            if ((count + 1) != (int(log2(i + 1)) + 1))
               res[i] = 0;
         }
         return res;
      }
   };

